CREATE OR REPLACE FUNCTION pkg_faktura.get_kunde (p_id bigint) RETURNS KUNDEN AS $body$
DECLARE

        v_row kunden%ROWTYPE;

BEGIN
        RAISE NOTICE 'pkg_faktura.get_kunde(%)', p_id;
        SELECT *
          INTO STRICT v_row
          FROM kunden
         WHERE id = p_id;
        RETURN v_row;
    EXCEPTION
        WHEN no_data_found THEN
            RAISE NOTICE '  -> Kunde nicht gefunden';
            RAISE EXCEPTION 'e_kunde_nicht_gefunden' USING ERRCODE = '50001';
    END;

$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
