CREATE OR REPLACE FUNCTION pkg_faktura.kunde_umsatz (p_kunde_id bigint) RETURNS bigint AS $body$
DECLARE

        v_summe bigint;

BEGIN
        RAISE NOTICE 'pkg_faktura.kunde_umsatz(%)', p_kunde_id;
        SELECT coalesce(SUM(betrag_brutto), 0)
          INTO STRICT v_summe
          FROM rechnungen
         WHERE kunden_id = p_kunde_id
           AND status    = 'BEZAHLT';
        RETURN v_summe;
    END;

$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION pkg_faktura.kunde_umsatz (p_kunde_id bigint) FROM PUBLIC;

