CREATE OR REPLACE FUNCTION pkg_faktura.berechne_rechnungssumme (p_rechnung_id bigint) RETURNS bigint AS $body$
DECLARE

        v_summe bigint;

BEGIN
        RAISE NOTICE 'pkg_faktura.berechne_rechnungssumme(%)', p_rechnung_id;
        SELECT coalesce(SUM(position_summe), 0)
          INTO STRICT v_summe
          FROM rechnungspositionen
         WHERE rechnung_id = p_rechnung_id;
        RETURN v_summe;
    END;

$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
