CREATE OR REPLACE PROCEDURE pkg_faktura.erstelle_kunde (p_vorname text, p_name text, p_email text, p_id INOUT bigint) AS $body$
BEGIN
        RAISE NOTICE 'pkg_faktura.erstelle_kunde(%)', p_email;
        INSERT INTO kunden(vorname, name, email)
             VALUES (p_vorname, p_name, p_email)
          RETURNING id INTO p_id;
        RAISE NOTICE '  -> neue Kunden-ID = %', p_id;
    END;

$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON PROCEDURE pkg_faktura.erstelle_kunde (p_vorname text, p_name text, p_email text, p_id INOUT bigint) FROM PUBLIC;

