CREATE OR REPLACE PROCEDURE pkg_faktura.setze_rechnungs_status (p_rechnung_id bigint, p_status text) AS $body$
DECLARE

        v_count bigint;

BEGIN
        RAISE NOTICE 'pkg_faktura.setze_rechnungs_status(%, %)', p_rechnung_id, p_status;

        IF p_status NOT IN ('OFFEN','BEZAHLT','MAHNUNG','STORNIERT') THEN
            RAISE NOTICE '  -> ungueltiger Status';
            RAISE EXCEPTION 'e_ungueltiger_status' USING ERRCODE = '50003';
        END IF;

        UPDATE rechnungen
           SET status = p_status
         WHERE id = p_rechnung_id;

        GET DIAGNOSTICS v_count = ROW_COUNT;
        IF v_count = 0 THEN
            RAISE NOTICE '  -> Rechnung nicht gefunden';
            RAISE EXCEPTION 'e_rechnung_nicht_gefunden' USING ERRCODE = '50002';
        END IF;

        RAISE NOTICE '  -> % Zeile(n) aktualisiert', v_count;
    END;

$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON PROCEDURE pkg_faktura.setze_rechnungs_status (p_rechnung_id bigint, p_status text) FROM PUBLIC;
